    {
      title: '验真员',
      dataIndex: 'assignee',
      width: 120,
    },
    {
      title: '截止时间',
      dataIndex: 'deadline_at',
      width: 160,
      render: (val) =>
        val ? new Date(val as string).toLocaleString('zh-CN') : '-',
    },
    {
      title: '佣金金额',
      dataIndex: 'commission_amount',
