        <Tag color={type === 'sale' ? 'blue' : 'green'}>
          {type === 'sale' ? '出售' : '出租'}
        </Tag>
      ),
    },
    {
      title: '价格',
      dataIndex: 'price',
      key: 'price',
      width: 120,
      render: (price: number, record: IHouse) => formatPrice(price, record.priceUnit),
    },
    {
      title: '面积',
      dataIndex: 'area',
      key: 'area',
      width: 100,
      render: (area: number) => `${area}m²`,
    },
