        <Col xs={24} sm={12} lg={6}>
          <Card loading={loading}>
            <Statistic
              title="总房源数"
              value={stats?.totalHouses || 0}
              prefix={<HomeOutlined />}
            />
          </Card>
        </Col>
        <Col xs={24} sm={12} lg={6}>
          <Card loading={loading}>
            <Statistic
              title="本月成交"
              value={stats?.monthDeals || 0}
              prefix={<CalendarOutlined />}
            />
          </Card>
        </Col>
        <Col xs={24} sm={12} lg={6}>
          <Card loading={loading}>
            <Statistic
              title="本月GMV"
              value={stats?.monthGMV || 0}
